(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"rental-yield",fields:[{"key":"purchasePrice","label":"매입가격","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"monthlyRent","label":"월 임대료","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"annualOperatingCost","label":"연간 운영비","type":"number","placeholder":"","default":"0","options":[],"raw":false}],hint:"취득비용·세금·대출이자·공실은 별도로 반영해야 합니다.",compute:function(x){var p=Number(x.purchasePrice),m=Number(x.monthlyRent),c=Number(x.annualOperatingCost);if(![p,m,c].every(Number.isFinite)||p<=0||m<0||c<0)return{error:"매입가격은 0보다 커야 합니다."};var gross=m*12,net=gross-c;return{grossIncome:gross,netIncome:net,grossYield:gross/p*100,netYield:net/p*100};},format:function(r,api){return api.resultCard("총 임대수익률",api.formatNumber(r.grossYield,6)+"%","")+api.resultCard("순 임대수익률",api.formatNumber(r.netYield,6)+"%","")+api.resultCard("연 순임대소득",api.formatWon(r.netIncome),"");}},{id:"vacancy-adjusted-rental-yield",fields:[{"key":"purchasePrice","label":"매입가격","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"monthlyRent","label":"만실 기준 월 임대료","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"occupancyRate","label":"예상 가동률 (%)","type":"number","placeholder":"","default":"90","options":[],"raw":false},{"key":"annualOperatingCost","label":"연간 운영비","type":"number","placeholder":"","default":"0","options":[],"raw":false}],hint:"",compute:function(x){var p=Number(x.purchasePrice),m=Number(x.monthlyRent),o=Number(x.occupancyRate)/100,c=Number(x.annualOperatingCost);if(![p,m,o,c].every(Number.isFinite)||p<=0||m<0||o<0||o>1||c<0)return{error:"가동률은 0% 이상 100% 이하로 입력해 주세요."};var effective=m*12*o,net=effective-c;return{effectiveIncome:effective,netIncome:net,netYield:net/p*100};},format:function(r,api){return api.resultCard("공실 반영 연 임대수입",api.formatWon(r.effectiveIncome),"")+api.resultCard("연 순임대소득",api.formatWon(r.netIncome),"")+api.resultCard("실효 순수익률",api.formatNumber(r.netYield,6)+"%","");}},{id:"deposit-loan-vs-rent",fields:[{"key":"loanAmount","label":"전세대출 금액","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"loanRate","label":"전세대출 연이율 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"monthlyRent","label":"비교 월세","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"annualLoanExtra","label":"전세 연간 추가비용","type":"number","placeholder":"","default":"0","options":[],"raw":false},{"key":"annualRentExtra","label":"월세 연간 추가비용","type":"number","placeholder":"","default":"0","options":[],"raw":false}],hint:"보증금의 기회비용·보증보험·관리비 차이 등은 추가비용 항목으로 직접 반영하세요.",compute:function(x){var l=Number(x.loanAmount),r=Number(x.loanRate)/100,m=Number(x.monthlyRent),le=Number(x.annualLoanExtra),re=Number(x.annualRentExtra);if(![l,r,m,le,re].every(Number.isFinite)||l<0||r<0||m<0||le<0||re<0)return{error:"입력값은 0 이상이어야 합니다."};var loanAnnual=l*r+le,rentAnnual=m*12+re,diff=Math.abs(loanAnnual-rentAnnual);return{loanAnnual:loanAnnual,rentAnnual:rentAnnual,monthlyLoan:loanAnnual/12,difference:diff,winner:loanAnnual===rentAnnual?"same":(loanAnnual<rentAnnual?"loan":"rent")};},format:function(r,api){var w=r.winner==="same"?"연간 비용 동일":(r.winner==="loan"?"전세대출 쪽이 저렴":"월세 쪽이 저렴");return api.resultCard("전세대출 월평균 비용",api.formatWon(r.monthlyLoan),"")+api.resultCard("월세 연간 비용",api.formatWon(r.rentAnnual),"")+api.resultCard(w,api.formatWon(r.difference)+" 차이","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
